from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of building‑related triples into a single fluent natural‑language sentence.
    """
    def clean(o: str) -> str:
        return o.strip('"').strip("'")

    clauses = []
    for t in triples:
        s, p, o = t.subject, t.predicate, clean(t.object)

        # Specific phrasing for common predicates
        if p == "capital":
            clauses.append(f"The capital of {s} is {o}")
        elif p == "leader":
            clauses.append(f"The leader of {s} is {o}")
        elif p == "currency":
            clauses.append(f"{s} uses the currency {o}")
        elif p == "location":
            clauses.append(f"{s} is located in {o}")
        elif p == "isPartOf":
            clauses.append(f"{s} is part of {o}")
        elif p == "buildingStartDate":
            clauses.append(f"Construction of {s} started in {o}")
        elif p == "completionDate":
            clauses.append(f"{s} was completed in {o}")
        elif p == "height":
            clauses.append(f"{s} rises to {o} metres")
        elif p == "architect":
            clauses.append(f"{s} was designed by {o}")
        elif p == "owner":
            clauses.append(f"{s} is owned by {o}")
        elif p == "floorCount":
            clauses.append(f"{s} has {o} floors")
        elif p == "floorArea":
            clauses.append(f"{s} has a floor area of {o} square metres")
        elif p == "cost":
            clauses.append(f"The cost of {s} is {o}")
        elif p == "buildingType":
            clauses.append(f"{s} is a {o}")
        elif p == "developer":
            clauses.append(f"{s} was developed by {o}")
        elif p == "tenant":
            clauses.append(f"{s} has a tenant {o}")
        elif p == "currentTenants":
            clauses.append(f"{s} currently houses {o}")
        elif p == "address":
            clauses.append(f"The address of {s} is {o}")
        elif p == "inaugurationDate":
            clauses.append(f"The inauguration of {s} was on {o}")
        elif p == "language":
            clauses.append(f"The language of {s} is {o}")
        elif p == "leaderTitle":
            clauses.append(f"The leader title of {s} is {o}")
        else:
            # Generic fallback
            clauses.append(f"{s} {p} {o}")

    if not clauses:
        return

